+f is_palindrome(text: &s) -> bool {
    v bytes: &[u8] = text.as_bytes();
    m i: usize = 0;
    m j: usize = bytes.len() - 1;
    loop {
        ? i >= j { ret 1b; }
        ? bytes[i] != bytes[j] { ret 0b; }
        i = i + 1;
        j = j - 1;
    }
}

rust_equivalent.rs_source:
pub fn is_palindrome(text: &str) -> bool {
    let bytes = text.as_bytes();
    let (mut i, mut j) = (0, bytes.len().saturating_sub(1));
    loop {
        if i >= j { return true; }
        if bytes[i] != bytes[j] { return false; }
        i += 1;
        j -= 1;
    }
}

