+f insertion_sort(arr: &![i32]~) {
    m i: usize = 1;
    loop {
        ? i >= arr.len() { break; }
        v key: i32 = arr[i];
        m j: i64 = i as i64 - 1;
        loop {
            ? j < 0 { break; }
            ? arr[j as usize] <= key { break; }
            arr[(j + 1) as usize] = arr[j as usize];
            j = j - 1;
        }
        arr[(j + 1) as usize] = key;
        i = i + 1;
    }
}

rust_equivalent.rs_source:
pub fn insertion_sort(arr: &mut Vec<i32>) {
    for i in 1..arr.len() {
        let key = arr[i];
        let mut j = i as i64 - 1;
        while j >= 0 && arr[j as usize] > key {
            arr[(j + 1) as usize] = arr[j as usize];
            j -= 1;
        }
        arr[(j + 1) as usize] = key;
    }
}

