+f popcount(n: u32) -> i32 {
    m count: i32 = 0;
    m val: u32 = n;
    loop {
        ? val == 0 { break; }
        count = count + (val & 1) as i32;
        val = val >> 1;
    }
    count
}

rust_equivalent.rs_source:
pub fn popcount(n: u32) -> i32 {
    let mut count = 0i32;
    let mut val = n;
    while val != 0 {
        count += (val & 1) as i32;
        val >>= 1;
    }
    count
}

