+f rotate_left(arr: [i32]~, k: usize) -> [i32]~ {
    v n: usize = arr.len();
    ? n == 0 { ret arr; }
    v shift: usize = k % n;
    m result: [i32]~ = [];
    m i: usize = shift;
    loop {
        ? i >= n { break; }
        result.push(arr[i]);
        i = i + 1;
    }
    m j: usize = 0;
    loop {
        ? j >= shift { break; }
        result.push(arr[j]);
        j = j + 1;
    }
    result
}

rust_equivalent.rs_source:
pub fn rotate_left(arr: Vec<i32>, k: usize) -> Vec<i32> {
    let n = arr.len();
    if n == 0 { return arr; }
    let shift = k % n;
    let mut result = Vec::new();
    for i in shift..n {
        result.push(arr[i]);
    }
    for j in 0..shift {
        result.push(arr[j]);
    }
    result
}

