+f first_primes(n: usize) -> [i64]~ {
    m primes: [i64]~ = [];
    m candidate: i64 = 2;
    loop {
        ? primes.len() >= n { break; }
        m is_p: bool = 1b;
        m i: usize = 0;
        loop {
            ? i >= primes.len() { break; }
            ? primes[i] * primes[i] > candidate { break; }
            ? candidate % primes[i] == 0 { is_p = 0b; break; }
            i = i + 1;
        }
        ? is_p { primes.push(candidate); }
        candidate = candidate + 1;
    }
    primes
}

rust_equivalent.rs_source:
pub fn first_primes(n: usize) -> Vec<i64> {
    let mut primes = Vec::new();
    let mut candidate = 2i64;
    while primes.len() < n {
        let mut is_p = true;
        for i in 0..primes.len() {
            if primes[i] * primes[i] > candidate { break; }
            if candidate % primes[i] == 0 { is_p = false; break; }
        }
        if is_p { primes.push(candidate); }
        candidate += 1;
    }
    primes
}

