+f transpose(matrix: [[i32]~]~) -> [[i32]~]~ {
    ? matrix.len() == 0 { ret []; }
    v rows: usize = matrix.len();
    v cols: usize = matrix[0].len();
    m result: [[i32]~]~ = [];
    m c: usize = 0;
    loop {
        ? c >= cols { break; }
        m row: [i32]~ = [];
        m r: usize = 0;
        loop {
            ? r >= rows { break; }
            row.push(matrix[r][c]);
            r = r + 1;
        }
        result.push(row);
        c = c + 1;
    }
    result
}

rust_equivalent.rs_source:
pub fn transpose(matrix: Vec<Vec<i32>>) -> Vec<Vec<i32>> {
    if matrix.is_empty() { return vec![]; }
    let rows = matrix.len();
    let cols = matrix[0].len();
    let mut result = Vec::new();
    for c in 0..cols {
        let mut row = Vec::new();
        for r in 0..rows {
            row.push(matrix[r][c]);
        }
        result.push(row);
    }
    result
}
